15	// PersonaLoaderImpl implements the PersonaLoader interface.
16	//
17	// A loader can own up to two source directories:
18	//   - libraryDir: read-only, shared across projects.
19	//   - projectDir: project-local (`.ddx/personas`). When a project persona has
20	//     the same name as a library persona, the project persona wins for that
21	//     project's bindings.
22	type PersonaLoaderImpl struct {
23		// libraryDir is the legacy single directory and remains in use when the
24		// loader is constructed via NewPersonaLoaderWithDir for test fixtures.
25		personasDir string
26		projectDir  string
27	}
28	
29	// NewPersonaLoader creates a new persona loader rooted at the project's
30	// working directory. It discovers the library path from config and the
31	// project-local `.ddx/personas` directory.
32	func NewPersonaLoader(workingDir string) PersonaLoader {
33		libraryDir := resolveLibraryPersonasDir(workingDir)
34		projectDir := resolveProjectPersonasDir(workingDir)
35		return &PersonaLoaderImpl{
36			personasDir: libraryDir,
37			projectDir:  projectDir,
38		}
39	}
40	
41	// NewPersonaLoaderWithDir creates a new persona loader with a specific
42	// library directory. Kept for tests and back-compat callers that only need
43	// the library source.
44	func NewPersonaLoaderWithDir(dir string) PersonaLoader {
45		return &PersonaLoaderImpl{
46			personasDir: dir,
47		}
48	}
49	
50	// NewPersonaLoaderWithDirs creates a loader with explicit library and project
51	// directories. Either may be empty to disable that source.
52	func NewPersonaLoaderWithDirs(libraryDir, projectDir string) PersonaLoader {
53		return &PersonaLoaderImpl{
54			personasDir: libraryDir,
55			projectDir:  projectDir,
56		}
57	}
58	
59	// resolveLibraryPersonasDir resolves the library persona directory.
60	func resolveLibraryPersonasDir(workingDir string) string {
61		cfg, err := config.LoadWithWorkingDir(workingDir)
62		if err != nil || cfg.Library == nil || cfg.Library.Path == "" {
63			homeDir, _ := os.UserHomeDir()
64			return filepath.Join(homeDir, ".ddx", "plugins", "ddx", "personas")
65		}
66		libPath := cfg.Library.Path
67		if !filepath.IsAbs(libPath) && workingDir != "" {
68			libPath = filepath.Join(workingDir, libPath)
69		}
70		return filepath.Join(libPath, "personas")
71	}
72	
73	// resolveProjectPersonasDir returns the project-local persona directory.
74	func resolveProjectPersonasDir(workingDir string) string {
75		if workingDir == "" {
76			return ""
77		}
78		return filepath.Join(workingDir, ".ddx", "personas")
79	}
80	
81	// LoadPersona loads a persona by name. Project-local personas override
82	// library personas with the same name.
83	func (l *PersonaLoaderImpl) LoadPersona(name string) (*Persona, error) {
84		if name == "" {
85			return nil, NewPersonaError(ErrorValidation, "persona name cannot be empty", nil)
86		}
87	
88		if l.projectDir != "" {
89			candidate := filepath.Join(l.projectDir, name+PersonaFileExtension)
90			if fileExists(candidate) {
91				return readPersonaFile(candidate, SourceProject)
92			}
93		}
94	
95		if l.personasDir != "" {
96			candidate := filepath.Join(l.personasDir, name+PersonaFileExtension)
97			if fileExists(candidate) {
98				return readPersonaFile(candidate, SourceLibrary)
99			}
100		}
101	
102		return nil, NewPersonaError(ErrorPersonaNotFound,
103			fmt.Sprintf("persona '%s' not found", name), nil)
104	}
105	
106	// readPersonaFile reads a single persona file and tags it with its source.
107	func readPersonaFile(filePath, source string) (*Persona, error) {
108		content, err := os.ReadFile(filePath)
109		if err != nil {
110			return nil, NewPersonaError(ErrorFileOperation,
111				fmt.Sprintf("failed to read persona file %s", filePath), err)
112		}
113		if len(content) > MaxPersonaFileSize {
114			return nil, NewPersonaError(ErrorValidation,
115				fmt.Sprintf("persona file %s exceeds maximum size of %d bytes", filePath, MaxPersonaFileSize), nil)
116		}
117		persona, err := parsePersona(content)
118		if err != nil {
119			return nil, NewPersonaError(ErrorInvalidPersona,
120				fmt.Sprintf("failed to parse persona %s", filePath), err)
121		}
122		persona.Source = source
123		persona.FilePath = filePath
124		return persona, nil
125	}
126	
127	// ListPersonas returns all available personas. Project personas override
128	// library personas of the same name; both sets are listed, with the project
129	// persona taking precedence when names collide.
130	func (l *PersonaLoaderImpl) ListPersonas() ([]*Persona, error) {
131		// Project personas first so they win on collision.
132		byName := map[string]*Persona{}
133		var ordered []string
134	
135		for _, dir := range []struct {
136			path   string
137			source string
138		}{
139			{l.projectDir, SourceProject},
140			{l.personasDir, SourceLibrary},
141		} {
142			if dir.path == "" || !dirExists(dir.path) {
143				continue
144			}
145			entries, err := os.ReadDir(dir.path)
146			if err != nil {
147				return nil, NewPersonaError(ErrorFileOperation,
148					fmt.Sprintf("failed to read personas directory %s", dir.path), err)
149			}
150			for _, entry := range entries {
151				if entry.IsDir() {
152					continue
153				}
154				if !strings.HasSuffix(entry.Name(), PersonaFileExtension) {
155					continue
156				}
157				if entry.Name() == "README.md" || entry.Name() == "readme.md" {
158					continue
159				}
160				personaName := strings.TrimSuffix(entry.Name(), PersonaFileExtension)
161				if _, seen := byName[personaName]; seen {
162					continue
163				}
164				persona, err := readPersonaFile(filepath.Join(dir.path, entry.Name()), dir.source)
165				if err != nil {
166					_, _ = fmt.Fprintf(os.Stderr, "Warning: Skipping invalid persona %s: %v\n", entry.Name(), err)
167					continue
168				}
169				byName[personaName] = persona
170				ordered = append(ordered, personaName)
171			}
172		}
173	
174		result := make([]*Persona, 0, len(byName))
175		for _, name := range ordered {
176			result = append(result, byName[name])
177		}
178		return result, nil
179	}
180	
181	// FindByRole returns personas that can fulfill the specified role.
182	func (l *PersonaLoaderImpl) FindByRole(role string) ([]*Persona, error) {
183		if role == "" {
184			return nil, NewPersonaError(ErrorValidation, "role cannot be empty", nil)
185		}
186	
187		allPersonas, err := l.ListPersonas()
188		if err != nil {
189			return nil, err
190		}
191	
192		var matchingPersonas []*Persona
193	
194		for _, persona := range allPersonas {
195			for _, personaRole := range persona.Roles {
196				if personaRole == role {
197					matchingPersonas = append(matchingPersonas, persona)
198					break
199				}
200			}
201		}
202	
203		return matchingPersonas, nil
204	}
205	
206	// FindByTags returns personas that have all the specified tags.
207	func (l *PersonaLoaderImpl) FindByTags(tags []string) ([]*Persona, error) {
208		if len(tags) == 0 {
209			return nil, NewPersonaError(ErrorValidation, "at least one tag must be specified", nil)
210		}
211	
212		allPersonas, err := l.ListPersonas()
213		if err != nil {
214			return nil, err
215		}
216	
217		var matchingPersonas []*Persona
218	
219		for _, persona := range allPersonas {
220			if hasAllTags(persona.Tags, tags) {
221				matchingPersonas = append(matchingPersonas, persona)
222			}
223		}
224	
225		return matchingPersonas, nil
226	}
227	
228	// parsePersona parses a persona from markdown content with YAML frontmatter.
229	func parsePersona(content []byte) (*Persona, error) {
230		frontmatter, markdownContent, err := splitFrontmatter(content)
231		if err != nil {
232			return nil, err
233		}
234	
235		var persona Persona
236		if err := yaml.Unmarshal(frontmatter, &persona); err != nil {
237			return nil, NewPersonaError(ErrorInvalidPersona, "failed to parse YAML frontmatter", err)
238		}
239	
240		persona.Content = string(markdownContent)
241	
242		if err := validatePersona(&persona); err != nil {
243			return nil, err
244		}
245	
246		return &persona, nil
247	}
248	
249	// splitFrontmatter splits YAML frontmatter from markdown content.
250	func splitFrontmatter(content []byte) (frontmatter []byte, markdown []byte, err error) {
251		scanner := bufio.NewScanner(bytes.NewReader(content))
252	
253		var lines []string
254		for scanner.Scan() {
255			lines = append(lines, scanner.Text())
256		}
257	
258		if len(lines) < 2 {
259			return nil, nil, NewPersonaError(ErrorInvalidPersona, "file too short to contain frontmatter", nil)
260		}
261	
262		if lines[0] != "---" {
263			return nil, nil, NewPersonaError(ErrorInvalidPersona, "missing YAML frontmatter (must start with ---)", nil)
264		}
265	
266		frontmatterEnd := -1
267		for i := 1; i < len(lines); i++ {
268			if lines[i] == "---" {
269				frontmatterEnd = i
270				break
271			}
272		}
273	
274		if frontmatterEnd == -1 {
275			return nil, nil, NewPersonaError(ErrorInvalidPersona, "unclosed YAML frontmatter (missing closing ---)", nil)
276		}
277	
278		frontmatterLines := lines[1:frontmatterEnd]
279		frontmatter = []byte(strings.Join(frontmatterLines, "\n"))
280	
281		var markdownLines []string
282		if frontmatterEnd+1 < len(lines) {
283			markdownLines = lines[frontmatterEnd+1:]
284			for len(markdownLines) > 0 && strings.TrimSpace(markdownLines[0]) == "" {
285				markdownLines = markdownLines[1:]
286			}
287		}
288	
289		markdown = []byte(strings.Join(markdownLines, "\n"))
290	
291		return frontmatter, markdown, nil
292	}
293	
294	// validatePersona validates that a persona has all required fields.
295	func validatePersona(persona *Persona) error {
296		if persona.Name == "" {
297			return NewPersonaError(ErrorValidation, "persona name is required", nil)
298		}
299	
300		if len(persona.Roles) == 0 {
301			return NewPersonaError(ErrorValidation, "persona must have at least one role", nil)
302		}
303	
304		if persona.Description == "" {
305			return NewPersonaError(ErrorValidation, "persona description is required", nil)
306		}
307	
308		if len(persona.Roles) > MaxRolesPerPersona {
309			return NewPersonaError(ErrorValidation,
310				fmt.Sprintf("persona cannot have more than %d roles", MaxRolesPerPersona), nil)
311		}
312	
313		if len(persona.Tags) > MaxTagsPerPersona {
314			return NewPersonaError(ErrorValidation,
315				fmt.Sprintf("persona cannot have more than %d tags", MaxTagsPerPersona), nil)
316		}
317	
318		if persona.Tags == nil {
319			persona.Tags = []string{}
320		}
321	
322		return nil
323	}
324	
325	// hasAllTags checks if a persona has all the specified tags.
326	func hasAllTags(personaTags []string, requiredTags []string) bool {
327		personaTagMap := make(map[string]bool)
328		for _, tag := range personaTags {
329			personaTagMap[tag] = true
330		}
331	
332		for _, requiredTag := range requiredTags {
333			if !personaTagMap[requiredTag] {
334				return false
335			}
336		}
337	
338		return true
339	}
340	
341	// fileExists checks if a file exists.
342	func fileExists(filePath string) bool {
343		_, err := os.Stat(filePath)
344		return !os.IsNotExist(err)
345	}
346	
347	// dirExists checks if a directory exists.
348	func dirExists(dirPath string) bool {
349		info, err := os.Stat(dirPath)
350		if os.IsNotExist(err) {
351			return false
352		}
353		if err != nil {
354			return false
355		}
356		return info.IsDir()
357	}
