1	package persona
2	
3	import (
4		"fmt"
5		"os"
6		"path/filepath"
7		"strings"
8	
9		"gopkg.in/yaml.v3"
10	)
11	
12	// ProjectPersonaWriter owns create/update/delete operations for project-local
13	// personas (files under `.ddx/personas/*.md`). Library personas are never
14	// mutated by this type; attempting to do so returns an ErrorReadOnlyLibrary.
15	type ProjectPersonaWriter struct {
16		workingDir string
17		loader     *PersonaLoaderImpl
18	}
19	
20	// NewProjectPersonaWriter returns a writer rooted at the given working
21	// directory. Passing an empty working dir returns a writer that errors on
22	// all calls because there is no project context.
23	func NewProjectPersonaWriter(workingDir string) *ProjectPersonaWriter {
24		loader := &PersonaLoaderImpl{
25			personasDir: resolveLibraryPersonasDir(workingDir),
26			projectDir:  resolveProjectPersonasDir(workingDir),
27		}
28		return &ProjectPersonaWriter{workingDir: workingDir, loader: loader}
29	}
30	
31	// Create writes a new project-local persona. Fails if a project persona
32	// with the same name already exists. A library persona with the same name
33	// is allowed (the project file will override it).
34	func (w *ProjectPersonaWriter) Create(name string, body string) (*Persona, error) {
35		if w.workingDir == "" {
36			return nil, NewPersonaError(ErrorNoProjectContext, "a project working directory is required to create a persona", nil)
37		}
38		if err := validateName(name); err != nil {
39			return nil, err
40		}
41		dir := w.loader.projectDir
42		if err := os.MkdirAll(dir, 0o755); err != nil {
43			return nil, NewPersonaError(ErrorFileOperation,
44				fmt.Sprintf("failed to create project personas directory %s", dir), err)
45		}
46		filePath := filepath.Join(dir, name+PersonaFileExtension)
47		if fileExists(filePath) {
48			return nil, NewPersonaError(ErrorAlreadyExists,
49				fmt.Sprintf("persona '%s' already exists at %s", name, filePath), nil)
50		}
51		normalized, err := normalizePersonaBody(name, body)
52		if err != nil {
53			return nil, err
54		}
55		if err := os.WriteFile(filePath, []byte(normalized), 0o644); err != nil {
56			return nil, NewPersonaError(ErrorFileOperation,
57				fmt.Sprintf("failed to write persona %s", filePath), err)
58		}
59		return readPersonaFile(filePath, SourceProject)
60	}
61	
62	// Update overwrites an existing project-local persona. If the target
63	// persona exists only as a library persona, the update is rejected with
64	// ErrorReadOnlyLibrary.
65	func (w *ProjectPersonaWriter) Update(name string, body string) (*Persona, error) {
66		if w.workingDir == "" {
67			return nil, NewPersonaError(ErrorNoProjectContext, "a project working directory is required to update a persona", nil)
68		}
69		if err := validateName(name); err != nil {
70			return nil, err
71		}
72		filePath := filepath.Join(w.loader.projectDir, name+PersonaFileExtension)
73		if !fileExists(filePath) {
74			// If a library persona exists, advise the user to fork first.
75			libraryPath := filepath.Join(w.loader.personasDir, name+PersonaFileExtension)
76			if fileExists(libraryPath) {
77				return nil, NewPersonaError(ErrorReadOnlyLibrary,
78					fmt.Sprintf("persona '%s' is a library persona and cannot be edited; fork it first", name), nil)
79			}
80			return nil, NewPersonaError(ErrorPersonaNotFound,
81				fmt.Sprintf("project persona '%s' not found", name), nil)
82		}
83		normalized, err := normalizePersonaBody(name, body)
84		if err != nil {
85			return nil, err
86		}
87		if err := os.WriteFile(filePath, []byte(normalized), 0o644); err != nil {
88			return nil, NewPersonaError(ErrorFileOperation,
89				fmt.Sprintf("failed to write persona %s", filePath), err)
90		}
91		return readPersonaFile(filePath, SourceProject)
92	}
93	
94	// Delete removes a project-local persona. Library personas are never
95	// deleted by this method.
96	func (w *ProjectPersonaWriter) Delete(name string) error {
97		if w.workingDir == "" {
98			return NewPersonaError(ErrorNoProjectContext, "a project working directory is required to delete a persona", nil)
99		}
100		if err := validateName(name); err != nil {
101			return err
102		}
103		filePath := filepath.Join(w.loader.projectDir, name+PersonaFileExtension)
104		if !fileExists(filePath) {
105			libraryPath := filepath.Join(w.loader.personasDir, name+PersonaFileExtension)
106			if fileExists(libraryPath) {
107				return NewPersonaError(ErrorReadOnlyLibrary,
108					fmt.Sprintf("persona '%s' is a library persona and cannot be deleted", name), nil)
109			}
110			return NewPersonaError(ErrorPersonaNotFound,
111				fmt.Sprintf("project persona '%s' not found", name), nil)
112		}
113		if err := os.Remove(filePath); err != nil {
114			return NewPersonaError(ErrorFileOperation,
115				fmt.Sprintf("failed to delete persona %s", filePath), err)
116		}
117		return nil
118	}
119	
120	// Fork copies a library persona into the project-local directory.
121	// `newName` may be empty to reuse the library name; if the target already
122	// exists, ErrorAlreadyExists is returned.
123	func (w *ProjectPersonaWriter) Fork(libraryName, newName string) (*Persona, error) {
124		if w.workingDir == "" {
125			return nil, NewPersonaError(ErrorNoProjectContext, "a project working directory is required to fork a persona", nil)
126		}
127		libraryPath := filepath.Join(w.loader.personasDir, libraryName+PersonaFileExtension)
128		if !fileExists(libraryPath) {
129			return nil, NewPersonaError(ErrorPersonaNotFound,
130				fmt.Sprintf("library persona '%s' not found", libraryName), nil)
131		}
132		targetName := newName
133		if targetName == "" {
134			targetName = libraryName
135		}
136		if err := validateName(targetName); err != nil {
137			return nil, err
138		}
139		content, err := os.ReadFile(libraryPath)
140		if err != nil {
141			return nil, NewPersonaError(ErrorFileOperation,
142				fmt.Sprintf("failed to read library persona %s", libraryPath), err)
143		}
144		if targetName != libraryName {
145			// Rewrite the frontmatter name so the forked file matches its new
146			// filename and is discoverable under the new name.
147			content = []byte(rewriteFrontmatterName(string(content), targetName))
148		}
149		if err := os.MkdirAll(w.loader.projectDir, 0o755); err != nil {
150			return nil, NewPersonaError(ErrorFileOperation,
151				fmt.Sprintf("failed to create project personas directory %s", w.loader.projectDir), err)
152		}
153		targetPath := filepath.Join(w.loader.projectDir, targetName+PersonaFileExtension)
154		if fileExists(targetPath) {
155			return nil, NewPersonaError(ErrorAlreadyExists,
156				fmt.Sprintf("persona '%s' already exists at %s", targetName, targetPath), nil)
157		}
158		if err := os.WriteFile(targetPath, content, 0o644); err != nil {
159			return nil, NewPersonaError(ErrorFileOperation,
160				fmt.Sprintf("failed to write forked persona %s", targetPath), err)
161		}
162		return readPersonaFile(targetPath, SourceProject)
163	}
164	
165	// ProjectDir returns the absolute path to the project-local persona dir.
166	func (w *ProjectPersonaWriter) ProjectDir() string { return w.loader.projectDir }
167	
168	// validateName keeps names safe for filesystem use.
169	func validateName(name string) error {
170		trimmed := strings.TrimSpace(name)
171		if trimmed == "" {
172			return NewPersonaError(ErrorValidation, "persona name cannot be empty", nil)
173		}
174		if strings.ContainsAny(trimmed, "/\\") || strings.HasPrefix(trimmed, ".") {
175			return NewPersonaError(ErrorValidation,
176				fmt.Sprintf("invalid persona name %q", name), nil)
177		}
178		return nil
179	}
180	
181	// normalizePersonaBody ensures the persona body has valid frontmatter and a
182	// name matching the file name. If the caller supplies a full markdown
183	// document with frontmatter, the frontmatter's name is forced to `name`.
184	// If the caller supplies raw body text without frontmatter, a minimal
185	// frontmatter block is synthesized.
186	func normalizePersonaBody(name string, body string) (string, error) {
187		body = strings.TrimLeft(body, "\n")
188		if body == "" {
189			return "", NewPersonaError(ErrorValidation, "persona body cannot be empty", nil)
190		}
191		if !strings.HasPrefix(body, "---") {
192			body = fmt.Sprintf("---\nname: %s\nroles: [general]\ndescription: %s\ntags: []\n---\n\n%s", name, name, body)
193		}
194		// Validate by parsing.
195		parsed, err := parsePersona([]byte(body))
196		if err != nil {
197			return "", err
198		}
199		if parsed.Name != name {
200			body = rewriteFrontmatterName(body, name)
201		}
202		return body, nil
203	}
204	
205	// rewriteFrontmatterName rewrites the `name:` key in a persona document's
206	// YAML frontmatter. If no frontmatter is present, the content is returned
207	// unchanged.
208	func rewriteFrontmatterName(content string, newName string) string {
209		lines := strings.Split(content, "\n")
210		if len(lines) == 0 || lines[0] != "---" {
211			return content
212		}
213		end := -1
214		for i := 1; i < len(lines); i++ {
215			if lines[i] == "---" {
216				end = i
217				break
218			}
219		}
220		if end == -1 {
221			return content
222		}
223		frontmatter := strings.Join(lines[1:end], "\n")
224		var node yaml.Node
225		if err := yaml.Unmarshal([]byte(frontmatter), &node); err != nil {
226			return content
227		}
228		// node.Content[0] is the document's mapping node.
229		if len(node.Content) == 0 {
230			return content
231		}
232		mapping := node.Content[0]
233		if mapping.Kind != yaml.MappingNode {
234			return content
235		}
236		foundName := false
237		for i := 0; i < len(mapping.Content); i += 2 {
238			if mapping.Content[i].Value == "name" {
239				mapping.Content[i+1].Value = newName
240				foundName = true
241				break
242			}
243		}
244		if !foundName {
245			mapping.Content = append([]*yaml.Node{
246				{Kind: yaml.ScalarNode, Value: "name"},
247				{Kind: yaml.ScalarNode, Value: newName},
248			}, mapping.Content...)
249		}
250		rewritten, err := yaml.Marshal(&node)
251		if err != nil {
252			return content
253		}
254		newFrontmatter := strings.TrimRight(string(rewritten), "\n")
255		var b strings.Builder
256		b.WriteString("---\n")
257		b.WriteString(newFrontmatter)
258		b.WriteString("\n---\n")
259		if end+1 < len(lines) {
260			b.WriteString(strings.Join(lines[end+1:], "\n"))
261		}
262		return b.String()
263	}
