35	// deprecatedPersonas lists personas from the pre-consolidation roster
36	// (pre-FEAT-011 Phase 3) that have been removed. The map is kept as empty
37	// to preserve the function signatures for future use if needed.
38	var deprecatedPersonas = map[string]string{}
39	
40	// deprecationNoticeFor returns a human-readable warning string (without
41	// a newline) for a deprecated persona, or empty if the name is current.
42	// Callers write it to stderr themselves so the caller controls framing.
43	func deprecationNoticeFor(name string) string {
44		replacement, deprecated := deprecatedPersonas[name]
45		if !deprecated {
46			return ""
47		}
48		if replacement != "" {
49			return fmt.Sprintf("warning: persona %q is deprecated and will be removed in a future release; use %q instead", name, replacement)
50		}
51		return fmt.Sprintf("warning: persona %q is deprecated and will be removed in a future release with no direct replacement; see library/personas/README.md for the current 5-persona roster", name)
52	}
