87	// runPersonaWithWorkingDir implements the persona command logic with working directory support
88	func runPersonaWithWorkingDir(cmd *cobra.Command, args []string, workingDir string) error {
89		// Extract flags from cobra.Command
90		listFlag, _ := cmd.Flags().GetBool("list")
91		showFlag, _ := cmd.Flags().GetString("show")
92		bindFlag, _ := cmd.Flags().GetString("bind")
93		roleFlag, _ := cmd.Flags().GetString("role")
94		roleFilter, _ := cmd.Flags().GetString("role")
95		tagFilter, _ := cmd.Flags().GetString("tag")
96	
97		// Handle subcommands
98		if len(args) > 0 {
99			switch args[0] {
100			case "list":
101				personas, err := personaList(workingDir, roleFilter, tagFilter)
102				if err != nil {
103					return err
104				}
105				return displayPersonaList(cmd, personas)
106			case "show":
107				if len(args) < 2 {
108					return fmt.Errorf("persona name required")
109				}
110				persona, err := personaShow(workingDir, args[1])
111				if err != nil {
112					return err
113				}
114				return displayPersona(cmd, persona)
115			case "bind":
116				if len(args) < 3 {
117					return fmt.Errorf("role and persona name required")
118				}
119				err := personaBind(workingDir, args[1], args[2])
120				if err != nil {
121					return err
122				}
123				_, _ = fmt.Fprintf(cmd.OutOrStdout(), "✅ Bound role '%s' to persona '%s'\n", args[1], args[2])
124				return nil
125			case "new":
126				if len(args) < 2 {
127					return fmt.Errorf("persona name required")
128				}
129				bodyFlag, _ := cmd.Flags().GetString("body")
130				created, err := personaNew(workingDir, args[1], bodyFlag)
131				if err != nil {
132					return err
133				}
134				_, _ = fmt.Fprintf(cmd.OutOrStdout(), "✅ Created project persona '%s' at %s\n", created.Name, created.FilePath)
135				return nil
136			case "edit":
137				if len(args) < 2 {
138					return fmt.Errorf("persona name required")
139				}
140				bodyFlag, _ := cmd.Flags().GetString("body")
141				updated, err := personaEdit(cmd, workingDir, args[1], bodyFlag)
142				if err != nil {
143					return err
144				}
145				_, _ = fmt.Fprintf(cmd.OutOrStdout(), "✅ Updated project persona '%s' at %s\n", updated.Name, updated.FilePath)
146				return nil
147			case "fork":
148				if len(args) < 2 {
149					return fmt.Errorf("persona name required")
150				}
151				asFlag, _ := cmd.Flags().GetString("as")
152				forked, err := personaFork(workingDir, args[1], asFlag)
153				if err != nil {
154					return err
155				}
156				_, _ = fmt.Fprintf(cmd.OutOrStdout(), "✅ Forked library persona '%s' to project persona '%s' at %s\n", args[1], forked.Name, forked.FilePath)
157				return nil
158			case "delete":
159				if len(args) < 2 {
160					return fmt.Errorf("persona name required")
161				}
162				if err := personaDelete(workingDir, args[1]); err != nil {
163					return err
164				}
165				_, _ = fmt.Fprintf(cmd.OutOrStdout(), "✅ Deleted project persona '%s'\n", args[1])
166				return nil
167			case "load":
168				loadedPersonas, err := personaLoad(workingDir, args[1:]...)
169				if err != nil {
170					return err
171				}
172				return displayLoadResult(cmd, args[1:], loadedPersonas)
173			case "bindings":
174				bindings, err := personaBindings(workingDir)
175				if err != nil {
176					return err
177				}
178				return displayBindings(cmd, bindings)
179			case "status":
180				status, err := personaStatus(workingDir)
181				if err != nil {
182					return err
183				}
184				return displayPersonaStatus(cmd, status)
185			}
186		}
187	
188		// Handle flags
189		if listFlag {
190			personas, err := personaList(workingDir, roleFilter, tagFilter)
191			if err != nil {
192				return err
193			}
194			return displayPersonaList(cmd, personas)
195		}
196	
197		if showFlag != "" {
198			persona, err := personaShow(workingDir, showFlag)
199			if err != nil {
200				return err
201			}
202			return displayPersona(cmd, persona)
203		}
204	
205		if bindFlag != "" && roleFlag != "" {
206			err := personaBind(workingDir, roleFlag, bindFlag)
207			if err != nil {
208				return err
209			}
210			_, _ = fmt.Fprintf(cmd.OutOrStdout(), "✅ Bound role '%s' to persona '%s'\n", roleFlag, bindFlag)
211			return nil
212		}
213	
214		// Show help when no flags or args provided
215		return cmd.Help()
216	}
