218	// displayPersonaList displays the list of personas to the user
219	func displayPersonaList(cmd *cobra.Command, personas []PersonaInfo) error {
220		if len(personas) == 0 {
221			_, _ = fmt.Fprintln(cmd.OutOrStdout(), "No personas found")
222			return nil
223		}
224	
225		_, _ = fmt.Fprintln(cmd.OutOrStdout(), "Available Personas:")
226		_, _ = fmt.Fprintln(cmd.OutOrStdout())
227	
228		// Create tabwriter for aligned output
229		w := tabwriter.NewWriter(cmd.OutOrStdout(), 0, 0, 2, ' ', 0)
230		_, _ = fmt.Fprintln(w, "PERSONA\tSOURCE\tROLE\tDESCRIPTION")
231		_, _ = fmt.Fprintln(w, "-------\t------\t----\t-----------")
232	
233		var deprecatedSeen []string
234		for _, p := range personas {
235			roleStr := "general"
236			if len(p.Roles) > 0 {
237				roleStr = p.Roles[0]
238			}
239			displayName := p.Name
240			if _, deprecated := deprecatedPersonas[p.Name]; deprecated {
241				displayName = p.Name + " (deprecated)"
242				deprecatedSeen = append(deprecatedSeen, p.Name)
243			}
244			source := p.Source
245			if source == "" {
246				source = "library"
247			}
248			_, _ = fmt.Fprintf(w, "%s\t%s\t%s\t%s\n", displayName, source, roleStr, p.Description)
249		}
250	
251		_ = w.Flush()
252	
253		// Emit a single aggregated deprecation notice on stderr so piped stdout
254		// stays clean. Individual notices go to stderr only when show/bind
255		// targets one deprecated persona directly.
256		for _, name := range deprecatedSeen {
257			if notice := deprecationNoticeFor(name); notice != "" {
258				_, _ = fmt.Fprintln(os.Stderr, notice)
259			}
260		}
261		return nil
262	}
