264	// displayPersona displays a single persona to the user
265	func displayPersona(cmd *cobra.Command, persona *PersonaInfo) error {
266		if persona == nil {
267			return fmt.Errorf("persona not found")
268		}
269	
270		// Emit the deprecation notice to stderr before the persona body so the
271		// warning is visible even when the caller pipes stdout elsewhere.
272		if notice := deprecationNoticeFor(persona.Name); notice != "" {
273			_, _ = fmt.Fprintln(os.Stderr, notice)
274		}
275	
276		// Parse metadata from content
277		metadata := parsePersonaMetadata(persona.Content)
278		if metadata != nil {
279			// Display formatted metadata
280			_, _ = fmt.Fprintf(cmd.OutOrStdout(), "Name: %s\n", metadata.Name)
281			_, _ = fmt.Fprintf(cmd.OutOrStdout(), "Roles: %s\n", strings.Join(metadata.Roles, ", "))
282			_, _ = fmt.Fprintf(cmd.OutOrStdout(), "Description: %s\n", metadata.Description)
283			_, _ = fmt.Fprintf(cmd.OutOrStdout(), "Tags: %s\n", strings.Join(metadata.Tags, ", "))
284	
285			// Display content after frontmatter
286			lines := strings.Split(persona.Content, "\n")
287			contentStart := 0
288			foundEnd := false
289			for i, line := range lines {
290				if i > 0 && line == "---" {
291					contentStart = i + 1
292					foundEnd = true
293					break
294				}
295			}
296			if foundEnd && contentStart < len(lines) {
297				_, _ = fmt.Fprintln(cmd.OutOrStdout())
298				_, _ = fmt.Fprint(cmd.OutOrStdout(), strings.Join(lines[contentStart:], "\n"))
299			}
300		} else {
301			// No frontmatter, display raw content
302			_, _ = fmt.Fprint(cmd.OutOrStdout(), persona.Content)
303		}
304		return nil
305	}
