378	// personaList returns a list of available personas, merging the library
379	// directory and project-local `.ddx/personas`. Project personas override
380	// library personas on name collision.
381	func personaList(workingDir string, roleFilter, tagFilter string) ([]PersonaInfo, error) {
382		libPath, err := getPersonaLibraryPath(workingDir)
383		libraryDir := ""
384		if err == nil {
385			libraryDir = filepath.Join(libPath, "personas")
386		}
387		projectDir := ""
388		if workingDir != "" {
389			projectDir = filepath.Join(workingDir, ".ddx", "personas")
390		}
391	
392		seen := map[string]bool{}
393		var personas []PersonaInfo
394	
395		// Project first so it wins on collision.
396		for _, src := range []struct {
397			dir    string
398			source string
399		}{
400			{projectDir, persona.SourceProject},
401			{libraryDir, persona.SourceLibrary},
402		} {
403			if src.dir == "" {
404				continue
405			}
406			entries, err := os.ReadDir(src.dir)
407			if os.IsNotExist(err) {
408				continue
409			}
410			if err != nil {
411				return nil, fmt.Errorf("failed to read personas directory %s: %w", src.dir, err)
412			}
413			for _, entry := range entries {
414				if entry.IsDir() || !strings.HasSuffix(entry.Name(), ".md") {
415					continue
416				}
417				name := strings.TrimSuffix(entry.Name(), ".md")
418				if seen[name] {
419					continue
420				}
421				filePath := filepath.Join(src.dir, entry.Name())
422				content, err := os.ReadFile(filePath)
423				if err != nil {
424					continue
425				}
426				metadata := parsePersonaMetadata(string(content))
427				if metadata == nil {
428					metadata = &PersonaMetadata{Name: name, Roles: []string{"general"}, Description: name}
429				}
430				if roleFilter != "" {
431					hasRole := false
432					for _, role := range metadata.Roles {
433						if role == roleFilter {
434							hasRole = true
435							break
436						}
437					}
438					if !hasRole {
439						continue
440					}
441				}
442				if tagFilter != "" {
443					hasTag := false
444					for _, tag := range metadata.Tags {
445						if tag == tagFilter {
446							hasTag = true
447							break
448						}
449					}
450					if !hasTag {
451						continue
452					}
453				}
454				personas = append(personas, PersonaInfo{
455					Name:        name,
456					Roles:       metadata.Roles,
457					Description: metadata.Description,
458					Tags:        metadata.Tags,
459					Content:     string(content),
460					FilePath:    filePath,
461					Source:      src.source,
462				})
463				seen[name] = true
464			}
465		}
466	
467		return personas, nil
468	}
