470	// personaShow returns detailed information about a specific persona,
471	// preferring the project-local file when a name collision exists.
472	func personaShow(workingDir string, personaName string) (*PersonaInfo, error) {
473		candidates := []struct {
474			path   string
475			source string
476		}{}
477		if workingDir != "" {
478			candidates = append(candidates, struct {
479				path   string
480				source string
481			}{filepath.Join(workingDir, ".ddx", "personas", personaName+".md"), persona.SourceProject})
482		}
483		if libPath, err := getPersonaLibraryPath(workingDir); err == nil {
484			candidates = append(candidates, struct {
485				path   string
486				source string
487			}{filepath.Join(libPath, "personas", personaName+".md"), persona.SourceLibrary})
488		}
489	
490		for _, candidate := range candidates {
491			if _, err := os.Stat(candidate.path); err == nil {
492				content, err := os.ReadFile(candidate.path)
493				if err != nil {
494					return nil, fmt.Errorf("failed to read persona: %w", err)
495				}
496				metadata := parsePersonaMetadata(string(content))
497				if metadata == nil {
498					metadata = &PersonaMetadata{Name: personaName, Roles: []string{"general"}, Description: personaName}
499				}
500				return &PersonaInfo{
501					Name:        personaName,
502					Roles:       metadata.Roles,
503					Description: metadata.Description,
504					Tags:        metadata.Tags,
505					Content:     string(content),
506					FilePath:    candidate.path,
507					Source:      candidate.source,
508				}, nil
509			}
510		}
511		return nil, fmt.Errorf("persona '%s' not found", personaName)
512	}
