514	// personaBind binds a role to a persona. Project-local personas satisfy
515	// existence checks alongside library personas.
516	func personaBind(workingDir string, role, personaName string) error {
517		projectPath := ""
518		if workingDir != "" {
519			projectPath = filepath.Join(workingDir, ".ddx", "personas", personaName+".md")
520		}
521		libPath, err := getPersonaLibraryPath(workingDir)
522		if err != nil {
523			return fmt.Errorf("failed to get library path: %w", err)
524		}
525		libraryPath := filepath.Join(libPath, "personas", personaName+".md")
526	
527		if projectPath != "" {
528			if _, perr := os.Stat(projectPath); perr == nil {
529				goto foundPersona
530			}
531		}
532		if _, perr := os.Stat(libraryPath); perr != nil {
533			return fmt.Errorf("persona '%s' not found (project: %s, library: %s)", personaName, projectPath, libraryPath)
534		}
535	foundPersona:
536	
537		// Emit a stderr deprecation warning when binding a role to a deprecated
538		// persona. Non-fatal — users migrate on their own timeline during the
539		// deprecation window.
540		if notice := deprecationNoticeFor(personaName); notice != "" {
541			_, _ = fmt.Fprintln(os.Stderr, notice)
542		}
543	
544		// Load only the local config file to preserve structure
545		configPath := ".ddx/config.yaml"
546		if workingDir != "" {
547			configPath = filepath.Join(workingDir, ".ddx/config.yaml")
548		}
549	
550		// Read current config as raw YAML node to preserve structure
551		data, err := os.ReadFile(configPath)
552		if err != nil {
553			return fmt.Errorf("failed to read config file %s: %w", configPath, err)
554		}
555	
556		var rootNode yaml.Node
557		if err := yaml.Unmarshal(data, &rootNode); err != nil {
558			return fmt.Errorf("failed to parse config: %w", err)
559		}
560	
561		// Find or create persona_bindings section
562		if err := addPersonaBindingToNode(&rootNode, role, personaName); err != nil {
563			return fmt.Errorf("failed to add persona binding: %w", err)
564		}
565	
566		// Write back to file
567		newData, err := yaml.Marshal(&rootNode)
568		if err != nil {
569			return fmt.Errorf("failed to marshal config: %w", err)
570		}
571	
572		if err := os.WriteFile(configPath, newData, 0644); err != nil {
573			return fmt.Errorf("failed to write config file %s: %w", configPath, err)
574		}
575	
576		return nil
577	}
