579	// personaBindings returns the current persona bindings
580	func personaBindings(workingDir string) (PersonaBindings, error) {
581		// Check if config file exists first (new format)
582		configPath := ".ddx/config.yaml"
583		if workingDir != "" {
584			configPath = filepath.Join(workingDir, ".ddx/config.yaml")
585		}
586	
587		if _, err := os.Stat(configPath); os.IsNotExist(err) {
588			return nil, fmt.Errorf("No .ddx/config.yaml configuration found")
589		}
590	
591		// Load config
592		cfg, err := loadPersonaConfig(workingDir)
593		if err != nil {
594			return nil, fmt.Errorf("failed to load configuration: %w", err)
595		}
596	
597		if cfg.PersonaBindings == nil {
598			return PersonaBindings{}, nil
599		}
600	
601		return PersonaBindings(cfg.PersonaBindings), nil
602	}
