604	// personaStatus returns the status of active personas
605	func personaStatus(workingDir string) (PersonaStatus, error) {
606		claudePath := "CLAUDE.md"
607		if workingDir != "" {
608			claudePath = filepath.Join(workingDir, "CLAUDE.md")
609		}
610	
611		status := PersonaStatus{
612			HasCLAUDEFile: false,
613		}
614	
615		// Check if CLAUDE.md exists
616		if _, err := os.Stat(claudePath); os.IsNotExist(err) {
617			return status, nil
618		}
619	
620		status.HasCLAUDEFile = true
621	
622		// Read CLAUDE.md
623		content, err := os.ReadFile(claudePath)
624		if err != nil {
625			return status, fmt.Errorf("failed to read CLAUDE.md: %w", err)
626		}
627	
628		// Parse loaded personas
629		claudeStr := string(content)
630		if strings.Contains(claudeStr, "<!-- PERSONAS:START -->") &&
631			strings.Contains(claudeStr, "<!-- PERSONAS:END -->") {
632			// Extract persona section
633			startIdx := strings.Index(claudeStr, "<!-- PERSONAS:START -->")
634			endIdx := strings.Index(claudeStr, "<!-- PERSONAS:END -->")
635			if startIdx != -1 && endIdx != -1 && endIdx > startIdx {
636				personaSection := claudeStr[startIdx:endIdx]
637	
638				// Parse loaded personas
639				lines := strings.Split(personaSection, "\n")
640				for _, line := range lines {
641					if strings.HasPrefix(line, "### ") {
642						// Parse role and persona from header
643						header := strings.TrimPrefix(line, "### ")
644						parts := strings.Split(header, ": ")
645						if len(parts) == 2 {
646							status.LoadedRoles = append(status.LoadedRoles, parts[0])
647							status.LoadedPersonas = append(status.LoadedPersonas, parts[1])
648						}
649					}
650				}
651			}
652		}
653	
654		// Get bindings count
655		cfg, err := loadPersonaConfig(workingDir)
656		if err == nil && cfg.PersonaBindings != nil {
657			status.BindingsCount = len(cfg.PersonaBindings)
658		}
659	
660		return status, nil
661	}
