663	// personaLoad loads personas into CLAUDE.md
664	func personaLoad(workingDir string, personas ...string) ([]string, error) {
665		// Always check if config file exists (new format)
666		configPath := ".ddx/config.yaml"
667		if workingDir != "" {
668			configPath = filepath.Join(workingDir, ".ddx/config.yaml")
669		}
670		if _, err := os.Stat(configPath); os.IsNotExist(err) {
671			return nil, fmt.Errorf("No .ddx/config.yaml configuration found")
672		}
673	
674		// Load config to get persona bindings
675		cfg, err := loadPersonaConfig(workingDir)
676		if err != nil {
677			return nil, fmt.Errorf("failed to load configuration: %w", err)
678		}
679	
680		loader := persona.NewPersonaLoader(workingDir)
681	
682		// Read CLAUDE.md if it exists
683		claudePath := "CLAUDE.md"
684		if workingDir != "" {
685			claudePath = filepath.Join(workingDir, "CLAUDE.md")
686		}
687	
688		var claudeContent string
689		if data, err := os.ReadFile(claudePath); err == nil {
690			claudeContent = string(data)
691		} else {
692			// Create new CLAUDE.md
693			claudeContent = "# CLAUDE.md\n\nProject guidance for my application."
694		}
695	
696		// Remove existing persona section if present
697		startMarker := "<!-- PERSONAS:START -->"
698		endMarker := "<!-- PERSONAS:END -->"
699		startIdx := strings.Index(claudeContent, startMarker)
700		if startIdx != -1 {
701			endIdx := strings.Index(claudeContent, endMarker)
702			if endIdx != -1 {
703				claudeContent = claudeContent[:startIdx] + claudeContent[endIdx+len(endMarker):]
704			}
705		}
706	
707		// Build persona content
708		var personaSection strings.Builder
709		personaSection.WriteString("\n" + startMarker + "\n")
710		personaSection.WriteString("## Active Personas\n\n")
711	
712		// Track loaded personas
713		loadedPersonas := []string{}
714	
715		// If specific personas requested, load those; otherwise load all bound personas
716		if len(personas) > 0 {
717			// Load specific personas
718			for _, personaName := range personas {
719				content, err := personaInjectionContent(loader, personaName)
720				if err != nil {
721					if isPersonaNotFound(err) {
722						return nil, fmt.Errorf("persona '%s' not found", personaName)
723					}
724					return nil, err
725				}
726				if err := validatePersonaContent(content, personaName); err != nil {
727					return nil, err
728				}
729				// Just add the content - personas have their own titles
730				personaSection.WriteString(content + "\n")
731				loadedPersonas = append(loadedPersonas, personaName)
732			}
733		} else {
734			// Load all bound personas from config
735			if cfg.PersonaBindings != nil {
736				for role, personaName := range cfg.PersonaBindings {
737					content, err := personaInjectionContent(loader, personaName)
738					if err != nil {
739						if isPersonaNotFound(err) {
740							continue
741						}
742						return nil, err
743					}
744					if err := validatePersonaContent(content, personaName); err != nil {
745						return nil, err
746					}
747					// Add role header with proper capitalization
748					caser := cases.Title(language.English)
749					capitalizedRole := caser.String(strings.ReplaceAll(role, "-", " "))
750					personaSection.WriteString(fmt.Sprintf("### %s: %s\n", capitalizedRole, personaName))
751					personaSection.WriteString(content + "\n")
752					loadedPersonas = append(loadedPersonas, personaName)
753				}
754			}
755		}
756	
757		personaSection.WriteString(endMarker + "\n")
758	
759		// Append persona section to CLAUDE.md
760		claudeContent += personaSection.String()
761	
762		// Write updated CLAUDE.md
763		if err := os.WriteFile(claudePath, []byte(claudeContent), 0644); err != nil {
764			return nil, fmt.Errorf("failed to write CLAUDE.md: %w", err)
765		}
766	
767		return loadedPersonas, nil
768	}
