794	// parsePersonaMetadata parses YAML frontmatter from persona content
795	func parsePersonaMetadata(content string) *PersonaMetadata {
796		lines := strings.Split(content, "\n")
797		if len(lines) == 0 || lines[0] != "---" {
798			return nil
799		}
800	
801		// Find end of frontmatter
802		endIdx := -1
803		for i := 1; i < len(lines); i++ {
804			if lines[i] == "---" {
805				endIdx = i
806				break
807			}
808		}
809	
810		if endIdx == -1 {
811			return nil
812		}
813	
814		// Parse YAML frontmatter
815		frontmatter := strings.Join(lines[1:endIdx], "\n")
816		var metadata PersonaMetadata
817		if err := yaml.Unmarshal([]byte(frontmatter), &metadata); err != nil {
818			return nil
819		}
820	
821		return &metadata
822	}
