824	// validatePersonaContent validates persona content structure
825	func validatePersonaContent(content, personaName string) error {
826		if strings.HasPrefix(content, "---\n") {
827			// Try to parse the frontmatter to validate it
828			lines := strings.Split(content, "\n")
829			endIdx := -1
830			for i := 1; i < len(lines); i++ {
831				if lines[i] == "---" {
832					endIdx = i
833					break
834				}
835			}
836			if endIdx > 0 {
837				frontmatter := strings.Join(lines[1:endIdx], "\n")
838				var metadata PersonaMetadata
839				if err := yaml.Unmarshal([]byte(frontmatter), &metadata); err != nil {
840					return fmt.Errorf("failed to parse YAML frontmatter in persona '%s': %w", personaName, err)
841				}
842			}
843		}
844		return nil
845	}
