911	// personaEdit updates a project-local persona. If bodyFile is empty, it
912	// opens $EDITOR on the file.
913	func personaEdit(cmd *cobra.Command, workingDir, name, bodyFile string) (*persona.Persona, error) {
914		if workingDir == "" {
915			return nil, fmt.Errorf("working directory must be provided")
916		}
917		writer := persona.NewProjectPersonaWriter(workingDir)
918	
919		if bodyFile != "" {
920			body, err := os.ReadFile(bodyFile)
921			if err != nil {
922				return nil, fmt.Errorf("failed to read body file %s: %w", bodyFile, err)
923			}
924			return writer.Update(name, string(body))
925		}
926	
927		// Interactive edit: open $EDITOR on the project file in place, then
928		// re-read to validate.
929		projectFile := filepath.Join(writer.ProjectDir(), name+".md")
930		if _, err := os.Stat(projectFile); os.IsNotExist(err) {
931			// Surface the same error the writer would.
932			if _, err := writer.Update(name, ""); err != nil {
933				return nil, err
934			}
935		}
936	
937		editor := os.Getenv("EDITOR")
938		if editor == "" {
939			editor = "vi"
940		}
941		editCmd := exec.Command(editor, projectFile) // #nosec G204 — intentional $EDITOR invocation
942		editCmd.Stdin = cmd.InOrStdin()
943		editCmd.Stdout = cmd.OutOrStdout()
944		editCmd.Stderr = cmd.ErrOrStderr()
945		if err := editCmd.Run(); err != nil {
946			return nil, fmt.Errorf("editor exited with error: %w", err)
947		}
948		data, err := os.ReadFile(projectFile)
949		if err != nil {
950			return nil, fmt.Errorf("failed to re-read persona after edit: %w", err)
951		}
952		return writer.Update(name, string(data))
953	}
