1011	// addPersonaBindingToNode adds or updates a persona binding in a YAML node tree
1012	func addPersonaBindingToNode(rootNode *yaml.Node, role, personaName string) error {
1013		// Find the document node
1014		var docNode *yaml.Node
1015		if rootNode.Kind == yaml.DocumentNode && len(rootNode.Content) > 0 {
1016			docNode = rootNode.Content[0]
1017		} else if rootNode.Kind == yaml.MappingNode {
1018			docNode = rootNode
1019		} else {
1020			return fmt.Errorf("invalid YAML structure")
1021		}
1022	
1023		if docNode.Kind != yaml.MappingNode {
1024			return fmt.Errorf("root node is not a mapping")
1025		}
1026	
1027		// Look for existing persona_bindings key
1028		for i := 0; i < len(docNode.Content); i += 2 {
1029			keyNode := docNode.Content[i]
1030			if keyNode.Value == "persona_bindings" {
1031				// Found existing persona_bindings, update it
1032				valueNode := docNode.Content[i+1]
1033				if valueNode.Kind != yaml.MappingNode {
1034					// Convert to mapping node
1035					valueNode.Kind = yaml.MappingNode
1036					valueNode.Content = []*yaml.Node{}
1037				}
1038	
1039				// Look for existing role or add new one
1040				found := false
1041				for j := 0; j < len(valueNode.Content); j += 2 {
1042					roleKeyNode := valueNode.Content[j]
1043					if roleKeyNode.Value == role {
1044						// Update existing role
1045						valueNode.Content[j+1].Value = personaName
1046						found = true
1047						break
1048					}
1049				}
1050	
1051				if !found {
1052					// Add new role-persona pair
1053					roleKeyNode := &yaml.Node{
1054						Kind:  yaml.ScalarNode,
1055						Value: role,
1056					}
1057					personaValueNode := &yaml.Node{
1058						Kind:  yaml.ScalarNode,
1059						Value: personaName,
1060					}
1061					valueNode.Content = append(valueNode.Content, roleKeyNode, personaValueNode)
1062				}
1063				return nil
1064			}
1065		}
1066	
1067		// persona_bindings key not found, add it
1068		bindingsKeyNode := &yaml.Node{
1069			Kind:  yaml.ScalarNode,
1070			Value: "persona_bindings",
1071		}
1072	
1073		roleKeyNode := &yaml.Node{
1074			Kind:  yaml.ScalarNode,
1075			Value: role,
1076		}
1077		personaValueNode := &yaml.Node{
1078			Kind:  yaml.ScalarNode,
1079			Value: personaName,
1080		}
1081	
1082		bindingsValueNode := &yaml.Node{
1083			Kind:    yaml.MappingNode,
1084			Content: []*yaml.Node{roleKeyNode, personaValueNode},
1085		}
1086	
1087		docNode.Content = append(docNode.Content, bindingsKeyNode, bindingsValueNode)
1088	
1089		return nil
1090	}
