504	func readComparisonRecords(workingDir string) ([]comparisonDispatchRecord, error) {
505		dir := filepath.Join(workingDir, ".ddx", "comparisons")
506		entries, err := os.ReadDir(dir)
507		if os.IsNotExist(err) {
508			return []comparisonDispatchRecord{}, nil
509		}
510		if err != nil {
511			return nil, err
512		}
513		records := make([]comparisonDispatchRecord, 0, len(entries))
514		for _, entry := range entries {
515			if entry.IsDir() || filepath.Ext(entry.Name()) != ".json" {
516				continue
517			}
518			data, err := os.ReadFile(filepath.Join(dir, entry.Name()))
519			if err != nil {
520				return nil, err
521			}
522			var record comparisonDispatchRecord
523			if err := json.Unmarshal(data, &record); err != nil {
524				return nil, fmt.Errorf("parsing comparison record %s: %w", entry.Name(), err)
525			}
526			if record.ID == "" {
527				continue
528			}
529			records = append(records, record)
530		}
531		sort.Slice(records, func(i, j int) bool {
532			if !records[i].CreatedAt.Equal(records[j].CreatedAt) {
533				return records[i].CreatedAt.After(records[j].CreatedAt)
534			}
535			return records[i].ID < records[j].ID
536		})
537		return records, nil
538	}
