572	func pluginCatalog(workingDir string) ([]*PluginInfo, error) {
573		reg := registry.BuiltinRegistry()
574		state, err := registry.LoadState()
575		if err != nil {
576			return nil, err
577		}
578	
579		byName := map[string]*PluginInfo{}
580		installedByName := map[string]registry.InstalledEntry{}
581		for _, entry := range state.Installed {
582			installedByName[entry.Name] = entry
583		}
584	
585		for _, pkg := range reg.Packages {
586			info := pluginInfoFromPackage(pkg, workingDir, installedByName[pkg.Name])
587			byName[info.Name] = info
588		}
589		for _, entry := range state.Installed {
590			if _, ok := byName[entry.Name]; ok {
591				continue
592			}
593			info := pluginInfoFromInstalled(entry, workingDir)
594			byName[info.Name] = info
595		}
596	
597		out := make([]*PluginInfo, 0, len(byName))
598		for _, info := range byName {
599			out = append(out, info)
600		}
601		sort.Slice(out, func(i, j int) bool { return out[i].Name < out[j].Name })
602		return out, nil
603	}
