768	type sessionEfficacyCacheEntry struct {
769		fingerprint string
770		snapshot    efficacySnapshot
771	}
772	
773	var sessionEfficacyCache struct {
774		sync.Mutex
775		byQuery map[string]sessionEfficacyCacheEntry
776	}
777	
778	func (r *queryResolver) efficacySnapshot(since, until, projectID *string) (efficacySnapshot, error) {
779		projectRoot := r.WorkingDir
780		if projectID != nil && strings.TrimSpace(*projectID) != "" {
781			projectRoot = r.projectRoot(strings.TrimSpace(*projectID))
782		}
783		startedAfter, err := parseOptionalEfficacyTime("since", since)
784		if err != nil {
785			return efficacySnapshot{}, err
786		}
787		startedBefore, err := parseOptionalEfficacyTime("until", until)
788		if err != nil {
789			return efficacySnapshot{}, err
790		}
791		logDir := agent.SessionLogDirForWorkDir(projectRoot)
792		query := agent.SessionIndexQuery{
793			StartedAfter:  startedAfter,
794			StartedBefore: startedBefore,
795		}
796		cacheKey := sessionEfficacyCacheKey(logDir, startedAfter, startedBefore)
797		fingerprint, err := sessionEfficacyIndexFingerprint(logDir, query)
798		if err != nil {
799			return efficacySnapshot{}, err
800		}
801		sessionEfficacyCache.Lock()
802		if sessionEfficacyCache.byQuery == nil {
803			sessionEfficacyCache.byQuery = map[string]sessionEfficacyCacheEntry{}
804		}
805		if cached, ok := sessionEfficacyCache.byQuery[cacheKey]; ok && cached.fingerprint == fingerprint {
806			sessionEfficacyCache.Unlock()
807			return cached.snapshot, nil
808		}
809		sessionEfficacyCache.Unlock()
810	
811		entries, err := agent.ReadSessionIndex(logDir, query)
812		if err != nil {
813			return efficacySnapshot{}, err
814		}
815		snap := buildEfficacySnapshotFromSessionEntries(entries)
816		sessionEfficacyCache.Lock()
817		sessionEfficacyCache.byQuery[cacheKey] = sessionEfficacyCacheEntry{fingerprint: fingerprint, snapshot: snap}
818		sessionEfficacyCache.Unlock()
819		return snap, nil
820	}
821	
822	func sessionEfficacyCacheKey(logDir string, startedAfter, startedBefore *time.Time) string {
823		return strings.Join([]string{logDir, timeKey(startedAfter), timeKey(startedBefore)}, "|")
824	}
825	
826	func timeKey(t *time.Time) string {
827		if t == nil {
828			return ""
