833	func sessionEfficacyIndexFingerprint(logDir string, query agent.SessionIndexQuery) (string, error) {
834		files, err := agent.SessionIndexShardFiles(logDir, query)
835		if err != nil {
836			return "", err
837		}
838		parts := make([]string, 0, len(files))
839		for _, file := range files {
840			info, err := os.Stat(file)
841			if os.IsNotExist(err) {
842				continue
843			}
844			if err != nil {
845				return "", err
846			}
847			parts = append(parts, fmt.Sprintf("%s:%d:%d", file, info.Size(), info.ModTime().UnixNano()))
848		}
849		return strings.Join(parts, "|"), nil
850	}
