945	func efficacyAttemptFromSession(entry agent.SessionIndexEntry) sessionEfficacyAttempt {
946		model := firstNonEmpty(entry.Model, "unknown")
947		provider := firstNonEmpty(entry.Provider, providerFromModel(model), entry.Harness, "unknown")
948		harness := firstNonEmpty(entry.Harness, provider, "unknown")
949		cost := efficacyCost(entry)
950		outcome := efficacyOutcome(entry)
951		return sessionEfficacyAttempt{
952			RowKey:       strings.Join([]string{harness, provider, model}, "|"),
953			BeadID:       entry.BeadID,
954			Outcome:      outcome,
955			Harness:      harness,
956			Provider:     provider,
957			Model:        model,
958			InputTokens:  entry.InputTokens,
959			OutputTokens: entry.OutputTokens,
960			DurationMs:   entry.DurationMS,
961			CostUsd:      cost,
962			EvidencePath: efficacyEvidencePath(entry),
963			CreatedAt:    entry.StartedAt,
964		}
965	}
