1129	func uniqueStrings(values []string) []string {
1130		seen := map[string]bool{}
1131		var out []string
1132		for _, value := range values {
1133			value = strings.TrimSpace(value)
1134			if value == "" || seen[value] {
1135				continue
1136			}
1137			seen[value] = true
1138			out = append(out, value)
1139		}
1140		sort.Strings(out)
1141		return out
1142	}
