34	async function mockGraphQL(page: Page) {
35		projectPersonas = [{ ...initialProjectPersona }];
36		boundBinding = null;
37		await page.route('/graphql', async (route) => {
38			const body = route.request().postDataJSON() as GqlBody;
39			const q = body.query;
40	
41			if (q.includes('NodeInfo')) {
42				await route.fulfill({
43					status: 200,
44					contentType: 'application/json',
45					body: JSON.stringify({ data: { nodeInfo: NODE_INFO } })
46				});
47				return;
48			}
49			if (q.includes('Projects')) {
50				await route.fulfill({
51					status: 200,
52					contentType: 'application/json',
53					body: JSON.stringify({
54						data: {
55							projects: {
56								edges: [{ node: { id: 'proj-1', name: 'Project', path: '/tmp/proj' } }]
57							}
58						}
59					})
60				});
61				return;
62			}
63	
64			if (q.includes('query Personas')) {
65				await route.fulfill({
66					status: 200,
67					contentType: 'application/json',
68					body: JSON.stringify({
69						data: { personas: [libraryPersona, ...projectPersonas] }
70					})
71				});
72				return;
73			}
74			if (q.includes('ProjectBindings')) {
75				await route.fulfill({
76					status: 200,
77					contentType: 'application/json',
78					body: JSON.stringify({ data: { projectBindings: '{}' } })
79				});
80				return;
81			}
82			if (q.includes('PersonaBind')) {
83				boundBinding = body.variables as { role: string; persona: string; projectId: string };
84				await route.fulfill({
85					status: 200,
86					contentType: 'application/json',
87					body: JSON.stringify({
88						data: {
89							personaBind: {
90								ok: true,
91								role: boundBinding.role,
92								persona: boundBinding.persona
93							}
94						}
95					})
96				});
97				return;
98			}
99			if (q.includes('PersonaCreate')) {
100				const vars = body.variables as { name: string; body: string };
101				projectPersonas.push({
102					...libraryPersona,
103					id: `persona-${vars.name}`,
104					name: vars.name,
105					description: `Project persona ${vars.name}`,
106					body: vars.body,
107					source: 'project',
108					filePath: `/proj/.ddx/personas/${vars.name}.md`
109				});
110				await route.fulfill({
111					status: 200,
112					contentType: 'application/json',
113					body: JSON.stringify({
114						data: {
115							personaCreate: {
116								id: `persona-${vars.name}`,
117								name: vars.name,
118								source: 'project'
119							}
120						}
121					})
122				});
123				return;
124			}
125			if (q.includes('PersonaUpdate')) {
126				const vars = body.variables as { name: string; body: string };
127				const p = projectPersonas.find((p) => p.name === vars.name);
128				if (p) {
129					p.description = `Updated ${vars.name}`;
130					p.body = vars.body;
131				}
132				await route.fulfill({
133					status: 200,
134					contentType: 'application/json',
135					body: JSON.stringify({
136						data: { personaUpdate: { id: `persona-${vars.name}`, name: vars.name, source: 'project' } }
137					})
138				});
139				return;
140			}
141			if (q.includes('PersonaDelete')) {
142				const vars = body.variables as { name: string };
143				projectPersonas = projectPersonas.filter((p) => p.name !== vars.name);
144				await route.fulfill({
145					status: 200,
146					contentType: 'application/json',
147					body: JSON.stringify({
148						data: { personaDelete: { ok: true, name: vars.name } }
149					})
150				});
151				return;
152			}
153			if (q.includes('PersonaFork')) {
154				const vars = body.variables as { libraryName: string; newName: string | null };
155				const target = vars.newName ?? vars.libraryName;
156				projectPersonas.push({
157					...libraryPersona,
158					id: `persona-${target}`,
159					name: target,
160					description: `Forked from ${vars.libraryName}`,
161					body: libraryPersona.body,
162					source: 'project',
163					filePath: `/proj/.ddx/personas/${target}.md`
164				});
165				await route.fulfill({
166					status: 200,
167					contentType: 'application/json',
168					body: JSON.stringify({
169						data: { personaFork: { id: `persona-${target}`, name: target, source: 'project' } }
170					})
171				});
172				return;
173			}
174			await route.continue();
175		});
176	}
